VALUES
  ('social-worker-moex-06800', 'social-worker', 'social-worker-moex-102-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作強調要充權案主，社會工作者必須小心那些伴隨著專業知識而出現的知識權威。若誤用專業知 識，充權工作反為解權工作（dis-empower）。對減少誤用專業知識，以下那一點並不適用？', '["放棄社工經驗累積的知識", "傾聽案主的心聲", "勿自認為是專家", "勿自以為是「客觀的觀察者」"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "9d32e5b6c8d6", "answer_pdf_sha1": "6bba627e5ea0", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06801', 'social-worker', 'social-worker-moex-102-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '醫務社會工作常使用社會醫療診斷模式來診斷病患及其所屬環境。Johnson（1992）認為社會暨心理診斷 的特質有九項，下列那一項不包括在特質裡？', '["需要判斷（judgement）的技術", "強調個別差異", "需具同理心", "案主與社工者互動的過程"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "9d32e5b6c8d6", "answer_pdf_sha1": "6bba627e5ea0", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06802', 'social-worker', 'social-worker-moex-102-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '在1997年少年事件處理法經大幅修正，旨在建立少年事件處理法的專業性，以貫徹「以保護代替管訓， 以教養代替處罰」之宗旨，也同時具有相當的特徵。這些特徵不包括：', '["違反少年事件處理法的少年，不得命其勞動服務", "少年事件規定由專設之機構處理", "審理之程序採取不公開制度", "注重少年保護處分之個別處遇政策"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "9d32e5b6c8d6", "answer_pdf_sha1": "6bba627e5ea0", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06803', 'social-worker', 'social-worker-moex-102-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社會工作者在執行個案處遇（置）計畫前，必定要先進行評估（assessment）工作，下列那些選項對評估', '["評估是一個針對案主問題進行資料蒐集的工作", "案主的口語陳述比起他 的非口語資訊來得真確", "評估是社工員後續協助案主總結成果的檢視", "評估有時是一個需要耗費時 日甚久的動態過程  ⑤評估工作進行時必須注意有無涉及法律議題"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "13ce809ec2ce", "answer_pdf_sha1": "99b28031b676", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06804', 'social-worker', 'social-worker-moex-102-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社工員與非自願性案主選擇與擬定處遇（置）目標時，社工員應該要注意：', '["運用同理心，降低非自願性案主的抗拒", "確定自己和非自願性案主的目標是一致的", "選擇處遇（置）目標的過程不因案主意願而有異", "不可以讓案主認為能和社工員討價還價"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "13ce809ec2ce", "answer_pdf_sha1": "99b28031b676", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06805', 'social-worker', 'social-worker-moex-102-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社會工作在個案結案時，就助人過程結果的成果（outcome）、過程（process）和滿意（satisfaction）三個 層面的評鑑（evaluation）上，下列陳述何者正確？', '["成果評鑑是指以機構的結案指標為該個案成果評鑑的通則來進行", "過程評鑑指的是社工員在服務的過程中能夠按照處遇（置）進度來提供服務", "過程評鑑可以加入案主重要他人對案主改變的評價，使評鑑訊息豐富", "滿意評鑑可以考慮使用量表測量來瞭解案主對社工員的服務滿意程度"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "13ce809ec2ce", "answer_pdf_sha1": "99b28031b676", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06806', 'social-worker', 'social-worker-moex-102-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列對於個案成功結案的陳述何者正確？①案主有相當的心理準備要與社工員結束關係  ②案主對社工', '["當案主沒有意願繼續處理問題，就結束案件", "案主的干預（介入）目標已經達成", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "13ce809ec2ce", "answer_pdf_sha1": "99b28031b676", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 4, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06807', 'social-worker', 'social-worker-moex-102-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列對於建立專業關係技巧的陳述，何者錯誤？', '["避免對案主的邏輯和感受作個人的評述", "對案主表達的真誠必須以不傷助人關係為限", "避免處理案主的憤怒，才能維持與案主的關係", "能夠果斷地與案主互動是開始面質的先決條件"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "13ce809ec2ce", "answer_pdf_sha1": "99b28031b676", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06808', 'social-worker', 'social-worker-moex-102-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列關於任務中心（task centered）取向的陳述，何者正確？', '["認為人有能力解決自己的問題，案主與社工員是夥伴", "強調短時間聚焦處理問題，但長時間處遇（置）會更為有效", "干預（介入）是基於案主情境的考量，而不是基於不同的理論", "干預（介入）實施僅限於使用在健康照顧、家庭和社區的範疇"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "13ce809ec2ce", "answer_pdf_sha1": "99b28031b676", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06809', 'social-worker', 'social-worker-moex-102-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列關於危機干預（介入）（crisis intervention）的陳述，何者正確？', '["危機分為可預期和非預期兩種", "評估的焦點放在未來的發展性", "危機干預（介入）的接觸時間為8-12週", "危機持續的時間不因人有差異"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "13ce809ec2ce", "answer_pdf_sha1": "99b28031b676", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
